-- CTE_Northwind_Demo.sql
-- Script estilo Northwind para SQL Server: solo estructura y datos actuales del demo CTE.
-- No incluye auditoria ni triggers; la auditoria se maneja aparte en PostgreSQL.

SET NOCOUNT ON;
GO

IF DB_ID(N'CTE_Northwind_Demo') IS NULL CREATE DATABASE [CTE_Northwind_Demo];
GO
USE [CTE_Northwind_Demo];
GO

IF OBJECT_ID(N'[Garantias]', N'U') IS NOT NULL DROP TABLE [Garantias];
IF OBJECT_ID(N'[Facturas]', N'U') IS NOT NULL DROP TABLE [Facturas];
IF OBJECT_ID(N'[Ordenes_Repuestos]', N'U') IS NOT NULL DROP TABLE [Ordenes_Repuestos];
IF OBJECT_ID(N'[Ordenes]', N'U') IS NOT NULL DROP TABLE [Ordenes];
IF OBJECT_ID(N'[Diagnosticos]', N'U') IS NOT NULL DROP TABLE [Diagnosticos];
IF OBJECT_ID(N'[Compras]', N'U') IS NOT NULL DROP TABLE [Compras];
IF OBJECT_ID(N'[Repuestos]', N'U') IS NOT NULL DROP TABLE [Repuestos];
IF OBJECT_ID(N'[Categorias_Repuestos]', N'U') IS NOT NULL DROP TABLE [Categorias_Repuestos];
IF OBJECT_ID(N'[Proveedores]', N'U') IS NOT NULL DROP TABLE [Proveedores];
IF OBJECT_ID(N'[Equipos]', N'U') IS NOT NULL DROP TABLE [Equipos];
IF OBJECT_ID(N'[Clientes]', N'U') IS NOT NULL DROP TABLE [Clientes];
IF OBJECT_ID(N'[Tecnicos]', N'U') IS NOT NULL DROP TABLE [Tecnicos];
IF OBJECT_ID(N'[Usuarios]', N'U') IS NOT NULL DROP TABLE [Usuarios];
GO

CREATE TABLE [Usuarios] (
  [id_usuario] INT NOT NULL,
  [nombre_usuario] NVARCHAR(100) NOT NULL,
  [contrasena_hash] NVARCHAR(255) NOT NULL,
  [correo_electronico] NVARCHAR(255) NULL,
  [rol] NVARCHAR(50) NOT NULL,
  [activo] BIT NOT NULL,
  [fecha_creacion] DATETIME2 NULL,
  CONSTRAINT [PK_Usuarios] PRIMARY KEY ([id_usuario])
);
GO

CREATE TABLE [Tecnicos] (
  [id_tecnico] INT NOT NULL,
  [usuario_id] INT NULL,
  [nombre] NVARCHAR(150) NOT NULL,
  [especialidad] NVARCHAR(255) NULL,
  [horario] NVARCHAR(100) NULL,
  [contacto] NVARCHAR(150) NULL,
  [activo] BIT NOT NULL,
  CONSTRAINT [PK_Tecnicos] PRIMARY KEY ([id_tecnico])
);
GO

CREATE TABLE [Clientes] (
  [id_cliente] INT NOT NULL,
  [nombre] NVARCHAR(150) NOT NULL,
  [telefono] NVARCHAR(50) NULL,
  [direccion] NVARCHAR(255) NULL,
  [correo] NVARCHAR(255) NULL,
  [contacto_secundario] NVARCHAR(100) NULL,
  [activo] BIT NOT NULL,
  CONSTRAINT [PK_Clientes] PRIMARY KEY ([id_cliente])
);
GO

CREATE TABLE [Equipos] (
  [id_equipo] INT NOT NULL,
  [cliente_id] INT NOT NULL,
  [marca] NVARCHAR(100) NULL,
  [tipo] NVARCHAR(100) NULL,
  [numero_serie] NVARCHAR(120) NULL,
  [modelo] NVARCHAR(150) NULL,
  CONSTRAINT [PK_Equipos] PRIMARY KEY ([id_equipo])
);
GO

CREATE TABLE [Proveedores] (
  [id_proveedor] INT NOT NULL,
  [nombre] NVARCHAR(150) NOT NULL,
  [telefono] NVARCHAR(50) NULL,
  [direccion] NVARCHAR(255) NULL,
  [correo] NVARCHAR(255) NULL,
  [web] NVARCHAR(255) NULL,
  [notas] NVARCHAR(MAX) NULL,
  [descontinuada] BIT NOT NULL,
  CONSTRAINT [PK_Proveedores] PRIMARY KEY ([id_proveedor])
);
GO

CREATE TABLE [Categorias_Repuestos] (
  [id_tipo_repuesto] INT NOT NULL,
  [nombre_tipo] NVARCHAR(150) NULL,
  [electronico] NVARCHAR(150) NULL,
  CONSTRAINT [PK_Categorias_Repuestos] PRIMARY KEY ([id_tipo_repuesto])
);
GO

CREATE TABLE [Repuestos] (
  [id_repuesto] INT NOT NULL,
  [tipo_repuesto_id] INT NOT NULL,
  [proveedor_id] INT NULL,
  [nombre] NVARCHAR(180) NULL,
  [descripcion] NVARCHAR(MAX) NULL,
  [costo_individual] DECIMAL(18,2) NULL,
  [porcentaje_de_ganacia] DECIMAL(18,2) NULL,
  [ganancia_cordobas] DECIMAL(18,2) NULL,
  [stock_actual] INT NOT NULL,
  [activo] BIT NOT NULL,
  [descontinuada] BIT NOT NULL,
  CONSTRAINT [PK_Repuestos] PRIMARY KEY ([id_repuesto])
);
GO

CREATE TABLE [Compras] (
  [id_compra] INT NOT NULL,
  [repuesto_id] INT NOT NULL,
  [proveedor_id] INT NOT NULL,
  [documento] NVARCHAR(100) NULL,
  [fecha_obtencion] DATETIME2 NULL,
  [cantidad] INT NULL,
  [costo_unitario] DECIMAL(18,2) NULL,
  [metodo_pago] NVARCHAR(50) NULL,
  CONSTRAINT [PK_Compras] PRIMARY KEY ([id_compra])
);
GO

CREATE TABLE [Diagnosticos] (
  [id_diagnostico] INT NOT NULL,
  [equipo_id] INT NOT NULL,
  [tecnico_id] INT NULL,
  [falla_reportada] NVARCHAR(MAX) NULL,
  [diagnostico_real] NVARCHAR(MAX) NULL,
  [presupuesto_estimado] DECIMAL(18,2) NULL,
  [prioridad] NVARCHAR(50) NULL,
  [fecha_hora] DATETIME2 NULL,
  [fecha_asignacion] DATETIME2 NULL,
  [estado_del_diagnostico] NVARCHAR(50) NOT NULL,
  [Estado_aprobacion] NVARCHAR(50) NOT NULL,
  [deja_cargador] BIT NOT NULL,
  [enciende] BIT NOT NULL,
  [usa_corriente_ac] BIT NOT NULL,
  CONSTRAINT [PK_Diagnosticos] PRIMARY KEY ([id_diagnostico])
);
GO

CREATE TABLE [Ordenes] (
  [id_orden] INT NOT NULL,
  [diagnostico_id] INT NOT NULL,
  [tecnico_id] INT NULL,
  [prioridad] NVARCHAR(50) NULL,
  [estado] NVARCHAR(50) NULL,
  [fecha_ingreso] DATETIME2 NULL,
  [resultado_final] NVARCHAR(50) NULL,
  [enciende_salida] BIT NULL,
  [usa_corriente_ac_salida] BIT NULL,
  [observacion_final] NVARCHAR(MAX) NULL,
  [fecha_cierre] DATETIME2 NULL,
  CONSTRAINT [PK_Ordenes] PRIMARY KEY ([id_orden])
);
GO

CREATE TABLE [Ordenes_Repuestos] (
  [id_detalle_repuesto] INT NOT NULL,
  [orden_id] INT NOT NULL,
  [repuesto_id] INT NULL,
  [pieza_solicitada] NVARCHAR(255) NULL,
  [cantidad_usada] INT NULL,
  [estado_aprobacion] NVARCHAR(50) NOT NULL,
  CONSTRAINT [PK_Ordenes_Repuestos] PRIMARY KEY ([id_detalle_repuesto])
);
GO

CREATE TABLE [Facturas] (
  [id_factura] INT NOT NULL,
  [orden_id] INT NOT NULL,
  [fecha_emision] DATETIME2 NULL,
  [monto_repuestos] DECIMAL(18,2) NULL,
  [mano_obra] DECIMAL(18,2) NULL,
  [subtotal] DECIMAL(18,2) NULL,
  [impuestos] DECIMAL(18,2) NULL,
  [total] DECIMAL(18,2) NULL,
  [metodo_pago] NVARCHAR(50) NULL,
  CONSTRAINT [PK_Facturas] PRIMARY KEY ([id_factura])
);
GO

CREATE TABLE [Garantias] (
  [id_garantia] INT NOT NULL,
  [factura_id] INT NOT NULL,
  [condiciones] NVARCHAR(MAX) NULL,
  [duracion_meses] INT NULL,
  [fecha_inicio] DATETIME2 NULL,
  [fecha_vencimiento] DATETIME2 NULL,
  CONSTRAINT [PK_Garantias] PRIMARY KEY ([id_garantia])
);
GO

-- Datos de Usuarios: 7 registros
GO

-- Datos de Tecnicos: 5 registros
GO

