-- Llaves foraneas y restricciones
ALTER TABLE [Tecnicos] ADD CONSTRAINT [FK_Tecnicos_Usuarios] FOREIGN KEY ([usuario_id]) REFERENCES [Usuarios]([id_usuario]);
ALTER TABLE [Equipos] ADD CONSTRAINT [FK_Equipos_Clientes] FOREIGN KEY ([cliente_id]) REFERENCES [Clientes]([id_cliente]);
ALTER TABLE [Repuestos] ADD CONSTRAINT [FK_Repuestos_Categorias] FOREIGN KEY ([tipo_repuesto_id]) REFERENCES [Categorias_Repuestos]([id_tipo_repuesto]);
ALTER TABLE [Repuestos] ADD CONSTRAINT [FK_Repuestos_Proveedores] FOREIGN KEY ([proveedor_id]) REFERENCES [Proveedores]([id_proveedor]);
ALTER TABLE [Compras] ADD CONSTRAINT [FK_Compras_Repuestos] FOREIGN KEY ([repuesto_id]) REFERENCES [Repuestos]([id_repuesto]);
ALTER TABLE [Compras] ADD CONSTRAINT [FK_Compras_Proveedores] FOREIGN KEY ([proveedor_id]) REFERENCES [Proveedores]([id_proveedor]);
ALTER TABLE [Diagnosticos] ADD CONSTRAINT [FK_Diagnosticos_Equipos] FOREIGN KEY ([equipo_id]) REFERENCES [Equipos]([id_equipo]);
ALTER TABLE [Diagnosticos] ADD CONSTRAINT [FK_Diagnosticos_Tecnicos] FOREIGN KEY ([tecnico_id]) REFERENCES [Tecnicos]([id_tecnico]);
ALTER TABLE [Ordenes] ADD CONSTRAINT [FK_Ordenes_Diagnosticos] FOREIGN KEY ([diagnostico_id]) REFERENCES [Diagnosticos]([id_diagnostico]);
ALTER TABLE [Ordenes] ADD CONSTRAINT [FK_Ordenes_Tecnicos] FOREIGN KEY ([tecnico_id]) REFERENCES [Tecnicos]([id_tecnico]);
ALTER TABLE [Ordenes_Repuestos] ADD CONSTRAINT [FK_Ordenes_Repuestos_Ordenes] FOREIGN KEY ([orden_id]) REFERENCES [Ordenes]([id_orden]);
ALTER TABLE [Ordenes_Repuestos] ADD CONSTRAINT [FK_Ordenes_Repuestos_Repuestos] FOREIGN KEY ([repuesto_id]) REFERENCES [Repuestos]([id_repuesto]);
ALTER TABLE [Facturas] ADD CONSTRAINT [FK_Facturas_Ordenes] FOREIGN KEY ([orden_id]) REFERENCES [Ordenes]([id_orden]);
ALTER TABLE [Garantias] ADD CONSTRAINT [FK_Garantias_Facturas] FOREIGN KEY ([factura_id]) REFERENCES [Facturas]([id_factura]);
ALTER TABLE [Facturas] ADD CONSTRAINT [UQ_Facturas_Orden] UNIQUE ([orden_id]);
ALTER TABLE [Garantias] ADD CONSTRAINT [UQ_Garantias_Factura] UNIQUE ([factura_id]);
GO

-- Conteo rapido
SELECT 'Usuarios' AS tabla, COUNT(*) AS registros FROM [Usuarios]
UNION ALL
SELECT 'Tecnicos' AS tabla, COUNT(*) AS registros FROM [Tecnicos]
UNION ALL
SELECT 'Clientes' AS tabla, COUNT(*) AS registros FROM [Clientes]
UNION ALL
SELECT 'Equipos' AS tabla, COUNT(*) AS registros FROM [Equipos]
UNION ALL
SELECT 'Proveedores' AS tabla, COUNT(*) AS registros FROM [Proveedores]
UNION ALL
SELECT 'Categorias_Repuestos' AS tabla, COUNT(*) AS registros FROM [Categorias_Repuestos]
UNION ALL
SELECT 'Repuestos' AS tabla, COUNT(*) AS registros FROM [Repuestos]
UNION ALL
SELECT 'Compras' AS tabla, COUNT(*) AS registros FROM [Compras]
UNION ALL
SELECT 'Diagnosticos' AS tabla, COUNT(*) AS registros FROM [Diagnosticos]
UNION ALL
SELECT 'Ordenes' AS tabla, COUNT(*) AS registros FROM [Ordenes]
UNION ALL
SELECT 'Ordenes_Repuestos' AS tabla, COUNT(*) AS registros FROM [Ordenes_Repuestos]
UNION ALL
SELECT 'Facturas' AS tabla, COUNT(*) AS registros FROM [Facturas]
UNION ALL
SELECT 'Garantias' AS tabla, COUNT(*) AS registros FROM [Garantias];
GO
